  constant RecMode_TriggerMask_c : RecMode_t := std_logic_vector(to_unsigned(1, RecMode_t'length));
  constant RecMode_SingleShot_c  : RecMode_t := std_logic_vector(to_unsigned(2, RecMode_t'length));
