  constant CtxStr_Sft_SCFG_OVERWRITE_c : integer                      := 8;
  constant CtxStr_Sft_SCFG_WINCNT_c    : integer                      := 16;
  constant CtxStr_Sft_SCFG_WINCUR_c    : integer                      := 24;

  type ToCtxWin_t is record
    Stream : integer range 0 to MaxStreams_c - 1;
